INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (1, "", "", "", 312, 3, "", 312002, 0.2, 101831, "nop_talk_joy1");
